// ============================================================
//  Servo + LEDs Power-Aware Demo
//  Arduino Uno — Beginner Friendly
// ============================================================
//  WIRING SUMMARY:
//   Servo  → Signal: D9 | VCC: External 5V | GND: Common GND
//   LED Red    → D5 → 220Ω → GND   (zone: 0°–60°)
//   LED Yellow → D6 → 220Ω → GND   (zone: 61°–120°)
//   LED Green  → D7 → 220Ω → GND   (zone: 121°–180°)
//   Button     → D2 → GND  (INPUT_PULLUP, pause/resume)
//
//  ⚠️ SAFETY NOTES:
//   • Servo powered by EXTERNAL 5V supply (NOT Arduino 5V pin)
//     to avoid overloading the Arduino's onboard regulator.
//   • External GND and Arduino GND share a common ground wire.
//   • Each LED uses a 220Ω resistor → ~14 mA per LED (safe).
//   • Button uses INPUT_PULLUP — no external resistor needed.
// ============================================================

#include <Servo.h>

// ---------- Pin Definitions ----------
const int SERVO_PIN   = 9;   // PWM pin for servo signal
const int LED_LEFT    = 5;   // Red LED    — zone 0°–60°
const int LED_CENTER  = 6;   // Yellow LED — zone 61°–120°
const int LED_RIGHT   = 7;   // Green LED  — zone 121°–180°
const int BTN_PIN     = 2;   // Pause/Resume button (INPUT_PULLUP)

// ---------- Servo & Motion ----------
Servo myServo;

int  currentAngle  = 0;      // Current servo position (degrees)
int  sweepStep     = 2;      // Degrees per update step (increase to go faster)
bool sweeping      = true;   // true = sweeping, false = paused

// ---------- Button Debounce ----------
bool     lastBtnState   = HIGH;  // HIGH because of INPUT_PULLUP
bool     paused         = false;
unsigned long lastDebounce = 0;
const unsigned long DEBOUNCE_DELAY = 50; // ms

// ---------- Sweep Timing ----------
unsigned long lastMoveTime = 0;
const unsigned long MOVE_INTERVAL = 20; // ms between each step (~50 Hz)

// =========================================================
void setup() {
  Serial.begin(9600);
  Serial.println("=== Servo + LEDs Power-Aware Demo ===");
  Serial.println("Button on D2: press to pause / resume.");

  // Attach servo to PWM pin
  myServo.attach(SERVO_PIN);
  myServo.write(currentAngle);

  // LED pins as outputs
  pinMode(LED_LEFT,   OUTPUT);
  pinMode(LED_CENTER, OUTPUT);
  pinMode(LED_RIGHT,  OUTPUT);

  // Button with internal pull-up (no external resistor needed)
  pinMode(BTN_PIN, INPUT_PULLUP);

  // Start with all LEDs off
  allLedsOff();

  delay(500); // Let servo settle
}

// =========================================================
void loop() {
  handleButton();   // Check pause/resume button
  if (!paused) {
    moveSweep();    // Advance servo one step if it's time
  }
  updateLeds();     // Always reflect current angle on LEDs
}

// =========================================================
// handleButton — debounced toggle on falling edge
// =========================================================
void handleButton() {
  bool reading = digitalRead(BTN_PIN);

  // Detect a change
  if (reading != lastBtnState) {
    lastDebounce = millis();
  }

  // Only act after debounce period
  if ((millis() - lastDebounce) > DEBOUNCE_DELAY) {
    // Falling edge = button just pressed (LOW because INPUT_PULLUP)
    if (reading == LOW && lastBtnState == HIGH) {
      paused = !paused;
      Serial.print(">> Servo ");
      Serial.println(paused ? "PAUSED" : "RESUMED");
    }
  }

  lastBtnState = reading;
}

// =========================================================
// moveSweep — advances angle, reverses at limits
// =========================================================
void moveSweep() {
  if (millis() - lastMoveTime < MOVE_INTERVAL) return;
  lastMoveTime = millis();

  currentAngle += sweepStep;

  // Reverse direction at boundaries
  if (currentAngle >= 180) {
    currentAngle = 180;
    sweepStep = -abs(sweepStep); // go backwards
  } else if (currentAngle <= 0) {
    currentAngle = 0;
    sweepStep = abs(sweepStep);  // go forwards
  }

  myServo.write(currentAngle);
}

// =========================================================
// updateLeds — light the LED matching the current zone
// =========================================================
void updateLeds() {
  allLedsOff();

  if (currentAngle <= 60) {
    digitalWrite(LED_LEFT,   HIGH); // Red    — Left zone
  } else if (currentAngle <= 120) {
    digitalWrite(LED_CENTER, HIGH); // Yellow — Center zone
  } else {
    digitalWrite(LED_RIGHT,  HIGH); // Green  — Right zone
  }
}

// =========================================================
// allLedsOff — convenience helper
// =========================================================
void allLedsOff() {
  digitalWrite(LED_LEFT,   LOW);
  digitalWrite(LED_CENTER, LOW);
  digitalWrite(LED_RIGHT,  LOW);
}

