# 🎛️ Servo + LEDs Power-Aware Demo — Full Project Report

---

## ⚠️ Auto-Correction Applied
> The power analyzer flagged the servo on the Arduino 5V rail (650 mA estimated draw vs. 200 mA limit). **Auto-corrected:** Servo VCC wire intentionally left disconnected from Arduino 5V — servo is powered exclusively by an **external 5V supply**. Only the signal wire (D9) and a shared GND run to the Arduino. This is the safe and intended design.

---

## 1️⃣ Wiring Table

| Component | Power Source | Arduino Pin | Notes |
|---|---|---|---|
| **Servo (signal)** | — | D9 (PWM) | Signal only; 1 kΩ–2.2 kΩ in series optional for extra protection |
| **Servo (VCC)** | ⚡ External 5V | — | **NOT** Arduino 5V — servo can draw 500–650 mA at stall |
| **Servo (GND)** | Common GND | GND | Ties external supply GND to Arduino GND |
| **LED Red** | Arduino D5 | D5 | Left zone (0°–60°) → 220Ω → GND |
| **LED Yellow** | Arduino D6 | D6 | Center zone (61°–120°) → 220Ω → GND |
| **LED Green** | Arduino D7 | D7 | Right zone (121°–180°) → 220Ω → GND |
| **R1/R2/R3** | — | — | 220Ω in series with each LED cathode to GND |
| **Pause Button** | INPUT_PULLUP | D2 | One leg → D2, other leg → GND; no external resistor |

---

## 2️⃣ Arduino Code (with comments)

```cpp
// ============================================================
//  Servo + LEDs Power-Aware Demo  |  Arduino Uno
// ============================================================
//  Servo      -> Signal: D9 | VCC: External 5V | GND: Common
//  LED Red    -> D5 -> 220Ω -> GND   (zone: 0–60°)
//  LED Yellow -> D6 -> 220Ω -> GND   (zone: 61–120°)
//  LED Green  -> D7 -> 220Ω -> GND   (zone: 121–180°)
//  Button     -> D2 -> GND  (INPUT_PULLUP, pause/resume)
// ============================================================

#include <Servo.h>

// --- Pin definitions ---
const int SERVO_PIN  = 9;   // PWM — servo signal wire (orange/white)
const int LED_LEFT   = 5;   // Red LED   — Left zone
const int LED_CENTER = 6;   // Yellow LED — Center zone
const int LED_RIGHT  = 7;   // Green LED  — Right zone
const int BTN_PIN    = 2;   // Pause/resume button

// --- Servo & motion state ---
Servo myServo;
int  currentAngle = 0;      // Current position in degrees
int  sweepStep    = 2;      // Step size in degrees per tick
bool paused       = false;  // Pause flag

// --- Button debounce state ---
bool          lastBtnState = HIGH; // HIGH = not pressed (INPUT_PULLUP)
unsigned long lastDebounce = 0;
const unsigned long DEBOUNCE_DELAY = 50; // ms

// --- Sweep timing ---
unsigned long lastMoveTime = 0;
const unsigned long MOVE_INTERVAL = 20; // ms (~50 updates/sec)

// ============================================================
void setup() {
  Serial.begin(9600);
  Serial.println("=== Servo + LEDs Power-Aware Demo ===");
  Serial.println("Press D2 button to pause / resume.");

  myServo.attach(SERVO_PIN);
  myServo.write(currentAngle); // Start at 0°

  pinMode(LED_LEFT,   OUTPUT);
  pinMode(LED_CENTER, OUTPUT);
  pinMode(LED_RIGHT,  OUTPUT);
  pinMode(BTN_PIN, INPUT_PULLUP); // Built-in pull-up, no resistor needed

  allLedsOff();
  delay(500); // Let servo settle before sweeping
}

// ============================================================
void loop() {
  handleButton();          // Check for pause/resume press
  if (!paused) moveSweep(); // Advance servo if running
  updateLeds();            // Always reflect zone on LEDs
}

// ============================================================
// handleButton — debounced toggle on falling edge
// ============================================================
void handleButton() {
  bool reading = digitalRead(BTN_PIN);
  if (reading != lastBtnState) lastDebounce = millis();

  if ((millis() - lastDebounce) > DEBOUNCE_DELAY) {
    // Falling edge = button just pressed
    if (reading == LOW && lastBtnState == HIGH) {
      paused = !paused;
      Serial.print(">> Servo "); Serial.println(paused ? "PAUSED" : "RESUMED");
    }
  }
  lastBtnState = reading;
}

// ============================================================
// moveSweep — non-blocking sweep using millis()
// ============================================================
void moveSweep() {
  if (millis() - lastMoveTime < MOVE_INTERVAL) return;
  lastMoveTime = millis();

  currentAngle += sweepStep;
  if (currentAngle >= 180) { currentAngle = 180; sweepStep = -2; } // Reverse
  else if (currentAngle <= 0) { currentAngle = 0;  sweepStep =  2; } // Forward

  myServo.write(currentAngle);
}

// ============================================================
// updateLeds — one LED on per zone, others off
// ============================================================
void updateLeds() {
  allLedsOff();
  if      (currentAngle <= 60)  digitalWrite(LED_LEFT,   HIGH); // 0–60°
  else if (currentAngle <= 120) digitalWrite(LED_CENTER, HIGH); // 61–120°
  else                          digitalWrite(LED_RIGHT,  HIGH); // 121–180°
}

void allLedsOff() {
  digitalWrite(LED_LEFT, LOW); digitalWrite(LED_CENTER, LOW); digitalWrite(LED_RIGHT, LOW);
}
```

